package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Constructor;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import static org.mockito.Mockito.*;

class ReflectionHelperTest {

  private static Object dummyRecordHelper;
  private static Method dummyMethod;
  private static Field dummyField;
  private static Field recordHelperField;

  @BeforeAll
  static void setup() throws Exception {
    dummyField = DummyClass.class.getDeclaredField("value");
    dummyMethod = DummyClass.class.getDeclaredMethod("getValue");

    recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Get the type of RECORD_HELPER field (RecordHelper)
    Class<?> recordHelperClass = recordHelperField.getType();

    // Create a Mockito mock instance of RecordHelper
    dummyRecordHelper = mock(recordHelperClass);

    // Use Mockito to stub the getAccessor method on the mock
    // Find the getAccessor method on the mock's class
    // Since dummyRecordHelper is a mock, we can cast to Object and use Mockito's when on the mock directly

    // Use Mockito's when().thenReturn() on the mock's method:
    // We have to use Mockito's doReturn().when() syntax with reflection proxy, so use Mockito's "mockingDetails" to get the mock

    // Since recordHelperClass is not an interface, we cannot use Proxy.
    // Instead, use Mockito's doAnswer to stub the method.

    // Stub getAccessor method via Mockito's doAnswer:
    java.lang.reflect.Method getAccessorMethod = recordHelperClass.getMethod("getAccessor", Class.class, Field.class);
    doAnswer(invocation -> dummyMethod)
      .when(dummyRecordHelper)
      .getClass()
      .getMethod("getAccessor", Class.class, Field.class)
      .invoke(dummyRecordHelper, DummyClass.class, dummyField);

    // The above does not work because of reflection invoke inside doAnswer.
    // Instead, use Mockito's when().thenReturn() on the mock with Mockito's 'when' and 'thenReturn' using Mockito's 'mock' with 'withSettings().defaultAnswer()'

    // The simplest way: Use Mockito's 'when' with the mock and cast to the appropriate class.

    // So cast dummyRecordHelper to Object and use Mockito's when:
    // But we don't have the interface type at compile time, so use Mockito's 'when' with reflection:

    // Use Mockito's 'when' with reflection:
    // But Mockito does not support stubbing via reflection invoke.

    // Alternative: Use Mockito's 'mock' with Answer that returns dummyMethod on getAccessor call.

    dummyRecordHelper = mock(recordHelperClass, invocation -> {
      if ("getAccessor".equals(invocation.getMethod().getName())
          && invocation.getArguments().length == 2) {
        return dummyMethod;
      }
      Class<?> returnType = invocation.getMethod().getReturnType();
      if (returnType.isPrimitive()) {
        if (returnType == boolean.class) return false;
        if (returnType == void.class) return null;
        if (returnType == byte.class) return (byte) 0;
        if (returnType == short.class) return (short) 0;
        if (returnType == int.class) return 0;
        if (returnType == long.class) return 0L;
        if (returnType == float.class) return 0f;
        if (returnType == double.class) return 0d;
        if (returnType == char.class) return '\0';
      }
      return null;
    });
  }

  @Test
  void getAccessor_returnsMethodFromRecordHelper() throws Exception {
    Object originalRecordHelper = recordHelperField.get(null);
    try {
      recordHelperField.set(null, dummyRecordHelper);

      Method result = ReflectionHelper.getAccessor(DummyClass.class, dummyField);
      assertNotNull(result);
      assertEquals(dummyMethod, result);
    } finally {
      recordHelperField.set(null, originalRecordHelper);
    }
  }

  private static class DummyClass {
    private int value;

    public int getValue() {
      return value;
    }
  }
}
